Code.Terraform:
```hcl
# 确保 WAF Classic 区域规则组至少有一条规则
resource "aws_wafregional_rule_group" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "<example_resource_name>"

  # 关键：添加一条规则，使规则组不为空
  activated_rule {
    priority = 1
    rule_id  = "<example_resource_id>"  # 现有规则 ID
    action {
      type = "BLOCK"
    }
  }
}
```
